import { useContext, useMemo, useState } from "react";
import { AuthContext } from "../context/AuthContext";
import { useNavigate } from "react-router-dom";
import "./Dashboard.css";

function Dashboard() {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  const [search, setSearch] = useState("");
  const [selectedType, setSelectedType] = useState("All");

  // FIRST 5 PETS FROM YOUR CSV
  // Paste image URLs into the image field
  const demoPets = [
    {
      id: 500,
      name: "Sky",
      type: "Bird",
      breed: "Parakeet",
      ageMonths: 131,
      color: "Orange",
      size: "Large",
      adoptionFee: 140,
      image: "PASTE_BIRD_IMAGE_URL_HERE",
      link: "https://example.com/pet/500"
    },
    {
      id: 501,
      name: "Hazel",
      type: "Rabbit",
      breed: "Rabbit",
      ageMonths: 73,
      color: "White",
      size: "Large",
      adoptionFee: 235,
      image: "PASTE_RABBIT_IMAGE_URL_HERE",
      link: "https://example.com/pet/501"
    },
    {
      id: 502,
      name: "Buddy",
      type: "Dog",
      breed: "Golden Retriever",
      ageMonths: 136,
      color: "Orange",
      size: "Medium",
      adoptionFee: 385,
      image: "PASTE_DOG_IMAGE_URL_HERE",
      link: "https://example.com/pet/502"
    },
    {
      id: 503,
      name: "Sunny",
      type: "Bird",
      breed: "Parakeet",
      ageMonths: 97,
      color: "White",
      size: "Small",
      adoptionFee: 217,
      image: "PASTE_BIRD_IMAGE_URL_HERE",
      link: "https://example.com/pet/503"
    },
    {
      id: 504,
      name: "Coco",
      type: "Rabbit",
      breed: "Rabbit",
      ageMonths: 123,
      color: "Gray",
      size: "Large",
      adoptionFee: 14,
      image: "PASTE_RABBIT_IMAGE_URL_HERE",
      link: "https://example.com/pet/504"
    }
  ];

  const filteredPets = useMemo(() => {
    return demoPets.filter((pet) => {
      const matchesSearch =
        pet.name.toLowerCase().includes(search.toLowerCase()) ||
        pet.type.toLowerCase().includes(search.toLowerCase()) ||
        pet.breed.toLowerCase().includes(search.toLowerCase());

      const matchesType =
        selectedType === "All" || pet.type === selectedType;

      return matchesSearch && matchesType;
    });
  }, [search, selectedType]);

  function handleLogout() {
    logout();
    navigate("/login");
  }

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <div>
          <h1>
            Welcome Back,{" "}
            {user
              ? user.username.charAt(0).toUpperCase() + user.username.slice(1)
              : "User"}
            !
          </h1>
        </div>

        <button className="logout-btn" onClick={handleLogout}>
          Logout
        </button>
      </div>

      <div className="search-section">
        <input
          className="search-input"
          type="text"
          placeholder="Search by pet name, type, or breed..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <select
          className="filter-select"
          value={selectedType}
          onChange={(e) => setSelectedType(e.target.value)}
        >
          <option value="All">All Types</option>
          <option value="Bird">Bird</option>
          <option value="Rabbit">Rabbit</option>
          <option value="Dog">Dog</option>
        </select>
      </div>

      <div className="pet-grid">
        {filteredPets.length > 0 ? (
          filteredPets.map((pet) => (
            <div className="pet-card" key={pet.id}>
              <img
                className="pet-image"
                src={pet.image}
                alt={pet.name}
                onError={(e) => {
                  e.target.src =
                    "https://via.placeholder.com/300x200?text=Paste+Image+URL";
                }}
              />

              <h3>{pet.name}</h3>
              <p className="pet-type">{pet.type}</p>

              <div className="pet-details">
                <p><strong>Breed:</strong> {pet.breed}</p>
                <p><strong>Age:</strong> {pet.ageMonths} months</p>
                <p><strong>Color:</strong> {pet.color}</p>
                <p><strong>Size:</strong> {pet.size}</p>
                <p><strong>Fee:</strong> ${pet.adoptionFee}</p>
              </div>

              <a
                className="details-btn"
                href={pet.link}
                target="_blank"
                rel="noreferrer"
              >
                More Details
              </a>
            </div>
          ))
        ) : (
          <p className="no-results">No pets found.</p>
        )}
      </div>
    </div>
  );
}

export default Dashboard;
